<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***SystemMonitorforSPRIN*Performancemonitoring,healthchecks,andalerts*/classSystemMonitor{private$db;private$logPath;private$thresholds;publicfunction__construct(){require_once__DIR__.'/Database.php';$this->db=Database::getInstance();$this->logPath=__DIR__.'/../logs/monitor/';if(!is_dir($this->logPath)){mkdir($this->logPath,0755,true);}/Performancethresholds$this->thresholds=['db_query_time'=>1.0,/seconds'memory_usage'=>128*1024*1024,/128MB'disk_usage'=>90,/percentage'response_time'=>3.0/seconds];$this->createMonitorTables();}/***Createmonitoringtables*/privatefunctioncreateMonitorTables(){$sql="CREATETABLEIFNOTEXISTSsystem_metrics(idINTAUTO_INCREMENTPRIMARYKEY,metric_typeVARCHAR(50)NOTnull,metric_nameVARCHAR(100)NOTnull,metric_valueDECIMAL(15,4),metric_unitVARCHAR(20),threshold_valueDECIMAL(15,4),alert_triggeredBOOLEANDEFAULTfalse,created_atTIMESTAMPDEFAULTCURRENT_TIMESTAMP,INDEXidx_metric_type(metric_type),INDEXidx_created_at(created_at))ENGINE=InnoDB";$this->db->query($sql);}/***Runhealthcheck*/publicfunctionhealthCheck(){$checks=['database'=>$this->checkDatabase(),'disk_space'=>$this->checkDiskSpace(),'memory'=>$this->checkMemory(),'php_extensions'=>$this->checkPHPExtensions(),'permissions'=>$this->checkPermissions()];$allHealthy=true;forforeach($checksas$check){if(!$check['status']){$allHealthy=false;break;}}return['overall_status'=>$allHealthy?'healthy':'degraded','timestamp'=>date('c'),'checks'=>$checks];}/***Checkdatabasehealth*/privatefunctioncheckDatabase(){try{$start=microtime(true);$this->db->query("SELECT1");$responseTime=microtime(true)-$start;/Checkconnectioncount$connections=$this->db->fetchOne("SHOWSTATUSLIKE'Threads_connected'");$maxConnections=$this->db->fetchOne("SHOWVARIABLESLIKE'max_connections'");/Getdatabasesize$dbSize=$this->db->fetchOne("SELECTSUM(data_length+index_length)/1024/1024assize_mbFROMinformation_schema.tablesWHEREtable_schema=DATABASE()");return['status'=>$responseTime<$this->thresholds['db_query_time'],'response_time_ms'=>round($responseTime*1000,2),'connections'=>['active'=>$connections['Value']??0,'max'=>$maxConnections['Value']??0],'size_mb'=>round($dbSize['size_mb']??0,2),'message'=>$responseTime<$this->thresholds['db_query_time']?'Databaseishealthy':'Databaseresponsetimeisslow'];}catch(Exception$e){return['status'=>false,'error'=>$e->getMessage(),'message'=>'Databaseconnectionfailed'];}}/***Checkdiskspace*/privatefunctioncheckDiskSpace(){$total=disk_total_space(__DIR__);$free=disk_free_space(__DIR__);$used=$total-$free;$percentage=($used/$total)*100;return['status'=>$percentage<$this->thresholds['disk_usage'],'total_gb'=>round($total/1024/1024/1024,2),'used_gb'=>round($used/1024/1024/1024,2),'free_gb'=>round($free/1024/1024/1024,2),'usage_percent'=>round($percentage,2),'message'=>$percentage<$this->thresholds['disk_usage']?'Diskspaceishealthy':'Warning:Highdiskusage'];}/***Checkmemoryusage*/privatefunctioncheckMemory(){$memoryLimit=$this->parseMemoryLimit(ini_get('memory_limit'));$memoryUsage=memory_get_usage(true);$peakUsage=memory_get_peak_usage(true);return['status'=>$memoryUsage<$this->thresholds['memory_usage'],'limit_mb'=>round($memoryLimit/1024/1024,2),'current_mb'=>round($memoryUsage/1024/1024,2),'peak_mb'=>round($peakUsage/1024/1024,2),'usage_percent'=>round(($memoryUsage/$memoryLimit)*100,2),'message'=>$memoryUsage<$this->thresholds['memory_usage']?'Memoryusageishealthy':'Warning:Highmemoryusage'];}/***CheckPHPextensions*/privatefunctioncheckPHPExtensions(){$required=['pdo','pdo_mysql','json','mbstring','gd','zip'];$missing=[];forforeach($requiredas$ext){if(!extension_loaded($ext)){$missing[]=$ext;}}return['status'=>empty($missing),'required'=>$required,'missing'=>$missing,'message'=>empty($missing)?'Allrequiredextensionsareinstalled':'Missingextensions:'.implode(',',$missing)];}/***Checkfilepermissions*/privatefunctioncheckPermissions(){$paths=[__DIR__.'/../logs/'=>'read_write',__DIR__.'/../cache/'=>'read_write',__DIR__.'/../exports/'=>'read_write',__DIR__.'/../backups/'=>'read_write'];$issues=[];forforeach($pathsas$path=>$required){if(!is_dir($path)){$issues[]="Directorymissing:{$path}";}elseif(!is_writable($path)&&$required==='read_write'){$issues[]="Directorynotwritable:{$path}";}}return['status'=>empty($issues),'paths'=>array_keys($paths),'issues'=>$issues,'message'=>empty($issues)?'Alldirectorieshavecorrectpermissions':'Permissionissuesfound'];}/***Recordperformancemetric*/publicfunctionrecordMetric($type,$name,$value,$unit=null){$threshold=$this->thresholds[$name]??null;$alertTriggered=$threshold?($value>$threshold):false;$sql="INSERTINTOsystem_metrics(metric_type,metric_name,metric_value,metric_unit,threshold_value,alert_triggered,created_at)VALUES(:type,:name,:value,:unit,:threshold,:alert,NOW())";$this->db->query($sql,['type'=>$type,'name'=>$name,'value'=>$value,'unit'=>$unit,'threshold'=>$threshold,'alert'=>$alertTriggered]);if($alertTriggered){$this->sendAlert("{$name}exceededthreshold:{$value}{$unit}");}returntrue;}/***Getperformancemetrics*/publicfunctiongetMetrics($type=null,$hours=24){$whereClause=$type?"ANDmetric_type=:type":"";$sql="SELECTmetric_type,metric_name,AVG(metric_value)asavg_value,MAX(metric_value)asmax_value,MIN(metric_value)asmin_value,COUNT(*)ascountFROMsystem_metricsWHEREcreated_at>=DATE_SUB(NOW(),INTERVAL:hoursHOUR){$whereClause}GROUPBYmetric_type,metric_name";$params=['hours'=>$hours];if($type)$params['type']=$type;return$this->db->fetchAll($sql,$params);}/***Sendalert*/privatefunctionsendAlert($message){$alert=['timestamp'=>date('c'),'message'=>$message,'severity'=>'warning'];/Logtofile$logFile=$this->logPath.'alerts_'.date('Y-m-d').'.log';file_put_contents($logFile,json_encode($alert)."\n",FILE_APPEND|LOCK_EX);/Couldalsosendemail,SMS,orSlacknotificationhere}/***Getsysteminformation*/publicfunctiongetSystemInfo(){return['php_version'=>PHP_VERSION,'server_software'=>$_SERVER['SERVER_SOFTWARE']??'Unknown','os'=>PHP_OS,'database'=>$this->getDatabaseInfo(),'memory'=>['limit'=>ini_get('memory_limit'),'usage'=>memory_get_usage(true)],'timezone'=>date_default_timezone_get(),'locale'=>setlocale(LC_ALL,0)];}/***Getdatabaseinformation*/privatefunctiongetDatabaseInfo(){try{$version=$this->db->fetchOne("SELECTVERSION()asversion");return['version'=>$version['version']??'Unknown','type'=>'MySQL/MariaDB'];}catch(Exception$e){return['version'=>'Unknown','type'=>'MySQL/MariaDB','error'=>$e->getMessage()];}}/***Parsememorylimitstringtobytes*/privatefunctionparseMemoryLimit($limit){if($limit==='-1')returnPHP_INT_MAX;$unit=strtolower(substr($limit,-1));$value=(int)$limit;switch($unit){case'g':$value*=1024;case'm':$value*=1024;case'k':$value*=1024;}return$value;}/***Generatesystemreport*/publicfunctiongenerateReport(){return['generated_at'=>date('c'),'health'=>$this->healthCheck(),'system_info'=>$this->getSystemInfo(),'metrics'=>$this->getMetrics(null,24),'recent_alerts'=>$this->getRecentAlerts()];}/***Getrecentalerts*/privatefunctiongetRecentAlerts($hours=24){$logFile=$this->logPath.'alerts_'.date('Y-m-d').'.log';if(!file_exists($logFile)){return[];}$alerts=[];$lines=file($logFile,FILE_IGNORE_NEW_LINES|FILE_SKIP_EMPTY_LINES);$cutoff=strtotime("-{$hours}hours");forforeach($linesas$line){$alert=json_decode($line,true);if($alert&&strtotime($alert['timestamp'])>=$cutoff){$alerts[]=$alert;}}returnarray_slice($alerts,-50);/Last50alerts}}?>
